/*
 * End-to-End Google Ads Conversion Tracking — application dataLayer contract
 *
 * Adapt within the application after server confirmation. Do NOT add this as a
 * blanket listener for HTML forms, and do not send PII to GA4.
 */

window.dataLayer = window.dataLayer || [];

function pushConfirmedLead(lead) {
  // lead.id must be an opaque, stable identifier generated by the server.
  window.dataLayer.push({
    event: 'generate_lead',
    lead_id: lead.id,
    form_id: lead.formId, // controlled value, e.g. 'demo_request'
    value: lead.expectedValue,
    currency: lead.currency,

    // Configure only the Google tag / enhanced-conversion data mapping to read
    // this. Never map this object into GA4 event parameters or custom dimensions.
    // Only include approved, user-supplied fields when consent policy permits.
    user_data: lead.adsMeasurementConsent ? {
      email: lead.email,
      phone_number: lead.phone,
      address: lead.address && {
        first_name: lead.address.firstName,
        last_name: lead.address.lastName,
        street: lead.address.street,
        city: lead.address.city,
        region: lead.address.region,
        postal_code: lead.address.postalCode,
        country: lead.address.country
      }
    } : undefined
  });
}

function pushConfirmedPurchase(order) {
  // Invoke exactly once after payment/order creation is confirmed server-side.
  window.dataLayer.push({
    event: 'purchase',
    transaction_id: order.id,
    value: order.total,
    currency: order.currency,
    items: order.items.map(function (item) {
      return {
        item_id: item.sku,
        item_name: item.name,
        price: item.price,
        quantity: item.quantity
      };
    }),
    user_data: order.adsMeasurementConsent ? {
      email: order.email,
      phone_number: order.phone
    } : undefined
  });
}
